  1	import * as React from 'react';
  2	import { getObjectVersionId } from '@odf/core/utils';
  3	import StaticDropdown from '@odf/shared/dropdown/StaticDropdown';
  4	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
  5	import { CommonModalProps } from '@odf/shared/modals';
  6	import { S3Commands } from '@odf/shared/s3';
  7	import { getName } from '@odf/shared/selectors';
  8	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  9	import { numberInputOnChange } from '@odf/shared/utils';
 10	import { DateTime } from 'luxon';
 11	import {
 12	  Modal,
 13	  ModalVariant,
 14	  Button,
 15	  ButtonVariant,
 16	  Alert,
 17	  AlertVariant,
 18	  FormGroup,
 19	  FormHelperText,
 20	  HelperText,
 21	  HelperTextItem,
 22	  ValidatedOptions,
 23	  NumberInput,
 24	  ClipboardCopy,
 25	} from '@patternfly/react-core';
 26	import { ObjectCrFormat } from '../../../types';
 27	import './presigned-modal.scss';
 28	
 29	// using same "key" and "value" in the enum on purpose, due to how "StaticDropdown" is implemented
 30	enum TimeUnits {
 31	  Hours = 'Hours',
 32	  Minutes = 'Minutes',
 33	}
 34	
 35	type PresignedURLModalProps = {
 36	  bucketName: string;
 37	  object: ObjectCrFormat;
 38	  s3Client: S3Commands;
 39	  showVersioning: boolean;
 40	};
 41	
 42	type URLExpiration = {
 43	  value: number;
 44	  unit: TimeUnits;
 45	};
 46	
 47	type URLDetails = {
 48	  url: string;
 49	  validUntil: string;
 50	};
 51	
 52	type ExpirationInputProps = {
 53	  urlExpiration: URLExpiration;
 54	  setURLExpiration: React.Dispatch<React.SetStateAction<URLExpiration>>;
 55	};
 56	
 57	type CopyURLProps = {
 58	  urlDetails: React.MutableRefObject<URLDetails>;
 59	};
 60	
 61	const ExpirationInput: React.FC<ExpirationInputProps> = ({
 62	  urlExpiration,
 63	  setURLExpiration,
 64	}) => {
 65	  const { t } = useCustomTranslation();
 66	
 67	  const inputValue = urlExpiration.value;
 68	  const minValue = 1;
 69	  const maxValue = urlExpiration.unit === TimeUnits.Minutes ? 720 : 12;
 70	
 71	  const onInputChange = (value: number) =>
 72	    setURLExpiration({ ...urlExpiration, value });
 73	  const onUnitChange = (unit: TimeUnits) =>
 74	    setURLExpiration({ value: minValue, unit });
 75	
 76	  return (
 77	    <FormGroup label={t('Expires after')} fieldId="expires-after">
 78	      <NumberInput
 79	        id="expires-after"
 80	        aria-label={t('Expires after')}
 81	        minusBtnAriaLabel={t('minus')}
 82	        plusBtnAriaLabel={t('plus')}
 83	        value={inputValue}
 84	        min={minValue}
 85	        max={maxValue}
 86	        onChange={numberInputOnChange(minValue, maxValue, onInputChange)}
 87	        onMinus={(): void => onInputChange(inputValue - 1)}
 88	        onPlus={(): void => onInputChange(inputValue + 1)}
 89	        className="pf-v6-u-mr-xs"
 90	      />
 91	      <StaticDropdown
 92	        defaultSelection={TimeUnits.Minutes}
 93	        dropdownItems={TimeUnits}
 94	        onSelect={onUnitChange}
 95	      />
 96	      <FormHelperText>
 97	        <HelperText>
 98	          <HelperTextItem variant={ValidatedOptions.default}>
 99	            {t('Validity period of the presigned URL.')}
100	          </HelperTextItem>
101	        </HelperText>
102	      </FormHelperText>
103	    </FormGroup>
104	  );
105	};
106	
107	const CopyURL: React.FC<CopyURLProps> = ({ urlDetails }) => {
108	  const { t } = useCustomTranslation();
109	
110	  return (
111	    <FormGroup label={t('Share link')} fieldId="share-link">
112	      <div className="pf-v5-u-text-align-right text-muted">
113	        <b>{t('Valid until: ')}</b>
114	        {urlDetails.current.validUntil}{' '}
115	      </div>
116	      <ClipboardCopy isReadOnly hoverTip={t('Copy')} clickTip={t('Copied')}>
117	        {urlDetails.current.url}
118	      </ClipboardCopy>
119	      <Alert
120	        variant={AlertVariant.info}
121	        className="pf-v6-u-mt-sm"
122	        isInline
123	        isPlain
124	        title={t(
125	          'This URL will automatically expire based on your configured time or when your current session expires.'
126	        )}
127	      />
128	    </FormGroup>
129	  );
130	};
131	
132	const PresignedURLModal: React.FC<CommonModalProps<PresignedURLModalProps>> = ({
133	  closeModal,
134	  isOpen,
135	  extraProps: { bucketName, object, s3Client, showVersioning },
136	}) => {
137	  const { t } = useCustomTranslation();
138	
139	  const urlDetails = React.useRef<URLDetails>({ url: null, validUntil: null });
140	  const [urlExpiration, setURLExpiration] = React.useState<URLExpiration>({
141	    value: 1,
142	    unit: TimeUnits.Minutes,
143	  });
144	  const [inProgress, setInProgress] = React.useState<boolean>(false);
145	  const [error, setError] = React.useState<Error>();
146	
147	  const objectName = getName(object);
148	  const urlCreated = !!urlDetails.current.url;
149	
150	  const onCopy = () => {
151	    navigator.clipboard.writeText(urlDetails.current.url);
152	  };
153	
154	  const onCreate = (event) => {
155	    event.preventDefault();
156	    setInProgress(true);
157	
158	    // in seconds
159	    const expiresIn =
160	      urlExpiration.value *
161	      (urlExpiration.unit === TimeUnits.Minutes ? 60 : 3600);
162	
163	    s3Client
164	      .getSignedUrl(
165	        {
166	          Bucket: bucketName,
167	          Key: objectName,
168	          ...(showVersioning && { VersionId: getObjectVersionId(object) }),
169	        },
170	        expiresIn
171	      )
172	      .then((url) => {
173	        urlDetails.current.url = url;
174	        urlDetails.current.validUntil = DateTime.now()
175	          .plus({ seconds: expiresIn })
176	          .toLocaleString(DateTime.DATETIME_FULL);
177	        setInProgress(false);
178	      })
179	      .catch((err) => {
180	        setError(err);
181	        setInProgress(false);
182	      });
183	  };
184	
185	  return (
186	    <Modal
187	      title={t('Share object with a presigned URL')}
188	      isOpen={isOpen}
189	      onClose={closeModal}
190	      description={
191	        <div className="text-muted">
192	          {t('Grant third-party access to an object for a limited time.')}
193	        </div>
194	      }
195	      variant={ModalVariant.medium}
196	      className="object-presigned-url--height"
197	      actions={[
198	        <ButtonBar
199	          inProgress={inProgress}
200	          errorMessage={error?.message || JSON.stringify(error)}
201	        >
202	          <span>
203	            <Button
204	              variant={ButtonVariant.primary}
205	              onClick={urlCreated ? onCopy : onCreate}
206	              isDisabled={!!error}
207	            >
208	              {urlCreated
209	                ? t('Copy presigned URL to clipboard')
210	                : t('Create presigned URL')}
211	            </Button>
212	            <Button variant={ButtonVariant.link} onClick={closeModal}>
213	              {urlCreated ? t('Close') : t('Cancel')}
214	            </Button>
215	          </span>
216	        </ButtonBar>,
217	      ]}
218	    >
219	      <div className="text-muted">
220	        <b>{t('Object: ')}</b>
221	        {objectName}
222	      </div>
223	      <Alert
224	        variant={AlertVariant.info}
225	        className="pf-v6-u-mt-sm pf-v6-u-mb-sm"
226	        isInline
227	        title={t(
228	          'A third-party entity can access the object using this presigned URL, which allows sharing without requiring a login, until the URL expires.'
229	        )}
230	      />
231	      {!error &&
232	        (urlCreated ? (
233	          <CopyURL urlDetails={urlDetails} />
234	        ) : (
235	          <ExpirationInput
236	            urlExpiration={urlExpiration}
237	            setURLExpiration={setURLExpiration}
238	          />
239	        ))}
240	    </Modal>
241	  );
242	};
243	
244	export default PresignedURLModal;

